__global__ void Fan1_cuda(float *m_dev,
                          float *a_dev,
                          float *b_dev,
                          const int size,
                          const int t) {
    int globalId = threadIdx.x + blockIdx.x * blockDim.x;

    if (globalId < size - 1 - t) {
        m_dev[size * (globalId + t + 1) + t] = a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

__global__ void Fan2_cuda(float *m_dev,
                          float *a_dev,
                          float *b_dev,
                          const int size,
                          const int t) {
    int globalIdx = threadIdx.x + blockIdx.x * blockDim.x;
    int globalIdy = threadIdx.y + blockIdx.y * blockDim.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -= m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -= m_dev[size * (globalIdx + 1 + t) + t] * b_dev[t];
        }
    }
}

void cudaErrorCheck(cudaError_t error, const char *msg, bool exitOnErr) {
    if (error != cudaSuccess) {
        printf("CUDA Error: %d %s %s\n", error, cudaGetErrorString(error), msg);
        if (exitOnErr) {
            exit(-1);
        }
    }
}

void create_matrix(float *m, int size) {
    int i, j;
    float lamda = -0.01;
    float coe[2 * size - 1];
    float coe_i = 0.0;

    for (i = 0; i < size; i) {
        coe_i = 10 * exp(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }
}

void InitPerRun(int size, float *m) {
    int i;
    for (i = 0; i < size * size; i++)
        *(m + i) = 0.0;
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    int i, j;

    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            fscanf(fp, "%f", ary + size * i + j);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    int i;

    for (i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    int i, j;

    for (i = 0; i < nrow; i++) {
        for (j = 0; j < ncol; j++) {
            printf("%8.2e ", *(ary + size * i + j));
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    int i;
    for (i = 0; i < ary_size; i++) {
        printf("%.2e ", ary[i]);
    }
    printf("\n\n");
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    int i, j;
    for (i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (j = 0; j < i; j) {
            finalVec[size - i - 1] -= *(a + size * (size - i - 1) + (size - j - 1)) * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] = finalVec[size - i - 1] / *(a + size * (size - i - 1) + (size - i - 1));
    }
}

float eventTime(cudaEvent_t event) {
    float elapsed;
    cudaErrorCheck(cudaEventElapsedTime(&elapsed, event, event), "ERROR in Event Profiling.", true);
    return elapsed;
}

void ForwardSub(cudaContext_t context, float *a, float *b, float *m, int size, int timing) {
    cudaEvent_t writeEvent, kernelEvent, readEvent;
    float writeMB = 0, readMB = 0;

    cudaDevice_t device;
    cudaErrorCheck(cudaGetDevice(&device), "Getting device", true);

    float *a_dev, *b_dev, *m_dev;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    cudaErrorCheck(cudaMalloc(&a_dev, sizeof(float) * size * size), "allocating a_dev", true);
    cudaErrorCheck(cudaMalloc(&b_dev, sizeof(float) * size), "allocating b_dev", true);
    cudaErrorCheck(cudaMalloc(&m_dev, sizeof(float) * size * size), "allocating m_dev", true);
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
    cudaEventCreate(&writeEvent);
#endif
    cudaErrorCheck(cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice), "Writing a_dev", true);
    cudaErrorCheck(cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice), "Writing b_dev", true);
    cudaErrorCheck(cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice), "Writing m_dev", true);
#ifdef TIMING
    cudaEventRecord(writeEvent);
    cudaEventSynchronize(writeEvent);
    h2d_time += eventTime(writeEvent);
    cudaEventDestroy(writeEvent);
#endif

    writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    dim3 globalWorksizeFan1(size, 1, 1);
    dim3 globalWorksizeFan2(size, size, 1);
    dim3 localWorksizeFan1(BLOCK_SIZE_0, 1, 1);
    dim3 localWorksizeFan2(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y, 1);

    int t;

    for (t = 0; t < (size - 1); t++) {
#ifdef TIMING
        cudaEventCreate(&kernelEvent);
#endif

        cudaLaunchConfig_t config1;
        config1.gridDim = dim3((size + BLOCK_SIZE_0 - 1) / BLOCK_SIZE_0, 1, 1);
        config1.blockDim = localWorksizeFan1;
        Fan1_cuda<<<config1.gridDim, config1.blockDim>>>(m_dev, a_dev, b_dev, size, t);
        cudaErrorCheck(cudaGetLastError(), "ERROR in Executing Fan1 Kernel", true);
#ifdef TIMING
        cudaEventRecord(kernelEvent);
        cudaEventSynchronize(kernelEvent);
        kernel_time += eventTime(kernelEvent);
        cudaEventDestroy(kernelEvent);
#endif

#ifdef TIMING
        cudaEventCreate(&kernelEvent);
#endif

        cudaLaunchConfig_t config2;
        config2.gridDim = dim3((size + BLOCK_SIZE_1_X - 1) / BLOCK_SIZE_1_X, 
                               (size + BLOCK_SIZE_1_Y - 1) / BLOCK_SIZE_1_Y, 1);
        config2.blockDim = localWorksizeFan2;
        Fan2_cuda<<<config2.gridDim, config2.blockDim>>>(m_dev, a_dev, b_dev, size, t);
        cudaErrorCheck(cudaGetLastError(), "ERROR in Executing Fan2 Kernel", true);
#ifdef TIMING
        cudaEventRecord(kernelEvent);
        cudaEventSynchronize(kernelEvent);
        kernel_time += eventTime(kernelEvent);
        cudaEventDestroy(kernelEvent);
#endif
    }

#ifdef TIMING
    cudaEventCreate(&readEvent);
#endif
    cudaErrorCheck(cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "Reading a_dev", true);
    cudaErrorCheck(cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost), "Reading b_dev", true);
    cudaErrorCheck(cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "Reading m_dev", true);
#ifdef TIMING
    cudaEventRecord(readEvent);
    cudaEventSynchronize(readEvent);
    d2h_time += eventTime(readEvent);
    cudaEventDestroy(readEvent);
#endif

    readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);
    cudaErrorCheck(cudaDeviceSynchronize(), "Synchronizing device", true);

#ifdef TIMING
    printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
    printf("%dx%d      \t", size, size);
    printf("%f [%.2fMB]\t", h2d_time, writeMB);
    printf("%f\t", kernel_time);
    printf("%f [%.2fMB]\t", d2h_time, readMB);
    printf("%f\n\n", h2d_time + kernel_time + d2h_time);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    cudaErrorCheck(cudaFree(a_dev), "Freeing a_dev", true);
    cudaErrorCheck(cudaFree(b_dev), "Freeing b_dev", true);
    cudaErrorCheck(cudaFree(m_dev), "Freeing m_dev", true);
#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif
}

int parseCommandline(int argc, char *argv[], char* filename,
                     int *q, int *v, int *t, int *p, int *d, int *size) {
    int i;
    if (argc < 2) return 1;
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 's':
                    i++;
                    *size = atoi(argv[i]);
                    printf("Create matrix internally in parse, size = %d \n", *size);
                    break;
                case 'f':
                    i++;
                    strncpy(filename, argv[i], 100);
                    printf("Read file from %s \n", filename);
                    break;
                case 'h':
                    return 1;
                    break;
                case 'q':
                    *q = 1;
                    break;
                case 'v':
                    *v = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

